import React, { Component } from "react";
import { Button, Col, Row, Container, ButtonGroup } from "react-bootstrap";

const SpellSlots = ({ charClass, charSubClass, level }) => {
  const [levelOne, setLevelOne] = React.useState(0);
  const [levelTwo, setLevelTwo] = React.useState(0);
  const [levelThree, setLevelThree] = React.useState(0);
  const [levelFour, setLevelFour] = React.useState(0);
  const [levelFive, setLevelFive] = React.useState(0);
  const [levelSix, setLevelSix] = React.useState(0);
  const [levelSeven, setLevelSeven] = React.useState(0);
  const [levelEight, setLevelEight] = React.useState(0);
  const [levelNine, setLevelNine] = React.useState(0);
  const [spellSlots, setSpellSlots] = React.useState([
    0, 0, 0, 0, 0, 0, 0, 0, 0,
  ]);
  const [slotLevels, setSlotLevels] = React.useState([
    1, 2, 3, 4, 5, 6, 7, 8, 9,
  ]);

  const FULL_CASTER = "fullCaster";
  const HALF_CASTER = "halfCaster";
  const THIRD_CASTER = "thirdCaster";
  const WARLOCK_CASTER = "warlockCaster";
  const NO_CASTER = "noCaster";

  const handleReset = () => {
    let slotsArr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    let classType = getClassType();
    if (classType === FULL_CASTER) {
      slotsArr = getFullSpellSlots();
    } else if (classType === HALF_CASTER) {
      slotsArr = getHalfSpellSlots();
    } else if (classType === THIRD_CASTER) {
      slotsArr = getThirdSpellSlots();
    } else if (classType === WARLOCK_CASTER) {
      slotsArr = getWarlockSpellSlots();
    }
    console.log(JSON.stringify(slotsArr));
    console.log(classType);
    setSpellSlots(slotsArr);
  };

  const incrementSlot = (slotLevel) => {
    let arr = spellSlots;
    arr[slotLevel] = arr[slotLevel] + 1;
    setSpellSlots({ ...arr });
  };

  function decrementSlot(slotLevel) {
    let arr = spellSlots;
    arr[slotLevel] = arr[slotLevel] - 1;
    setSpellSlots({ ...arr });
  }

  const getClassType = () => {
    console.log(charClass);
    console.log(charSubClass);
    console.log(level);
    if (
      charClass === "Bard" ||
      charClass === "Cleric" ||
      charClass === "Druid" ||
      charClass === "Sorcerer" ||
      charClass === "Wizard"
    ) {
      return FULL_CASTER;
    } else if (
      charClass === "Paladin" ||
      charClass === "Ranger" ||
      charClass === "Artificer"
    ) {
      return HALF_CASTER;
    } else if (
      charSubClass === "Arcane Trickster" ||
      charSubClass === "Eldritch Knight"
    ) {
      return THIRD_CASTER;
    } else if (charClass === "Warlock") {
      return WARLOCK_CASTER;
    } else {
      return NO_CASTER;
    }
  };

  const getFullSpellSlots = () => {
    let arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    let lvl = parseInt(level);
    if (lvl === 1) {
      arr = [2, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 2) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 3) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 4) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 5) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 6) {
      arr = [4, 3, 3, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 7) {
      arr = [4, 3, 3, 1, 0, 0, 0, 0, 0];
    } else if (lvl === 8) {
      arr = [4, 3, 3, 2, 0, 0, 0, 0, 0];
    } else if (lvl === 9) {
      arr = [4, 3, 3, 3, 1, 0, 0, 0, 0];
    } else if (lvl === 10) {
      arr = [4, 3, 3, 3, 2, 0, 0, 0, 0];
    } else if (lvl === 11) {
      arr = [4, 3, 3, 3, 2, 1, 0, 0, 0];
    } else if (lvl === 12) {
      arr = [4, 3, 3, 3, 2, 1, 0, 0, 0];
    } else if (lvl === 13) {
      arr = [4, 3, 3, 3, 2, 1, 1, 0, 0];
    } else if (lvl === 14) {
      arr = [4, 3, 3, 3, 2, 1, 1, 0, 0];
    } else if (lvl === 15) {
      arr = [4, 3, 3, 3, 2, 1, 1, 1, 0];
    } else if (lvl === 16) {
      arr = [4, 3, 3, 3, 2, 1, 1, 1, 0];
    } else if (lvl === 17) {
      arr = [4, 3, 3, 3, 2, 1, 1, 1, 1];
    } else if (lvl === 18) {
      arr = [4, 3, 3, 3, 3, 1, 1, 1, 1];
    } else if (lvl === 19) {
      arr = [4, 3, 3, 3, 3, 2, 1, 1, 1];
    } else if (lvl === 20) {
      arr = [4, 3, 3, 3, 3, 2, 2, 1, 1];
    }
    return arr;
  };
  const getHalfSpellSlots = () => {
    let arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    let lvl = parseInt(level);
    if (lvl === 1) {
      arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 2) {
      arr = [2, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 3) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 4) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 5) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 6) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 7) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 8) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 9) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 10) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 11) {
      arr = [4, 3, 3, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 12) {
      arr = [4, 3, 3, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 13) {
      arr = [4, 3, 3, 1, 0, 0, 0, 0, 0];
    } else if (lvl === 14) {
      arr = [4, 3, 3, 1, 0, 0, 0, 0, 0];
    } else if (lvl === 15) {
      arr = [4, 3, 3, 2, 0, 0, 0, 0, 0];
    } else if (lvl === 16) {
      arr = [4, 3, 3, 2, 0, 0, 0, 0, 0];
    } else if (lvl === 17) {
      arr = [4, 3, 3, 3, 1, 0, 0, 0, 0];
    } else if (lvl === 18) {
      arr = [4, 3, 3, 3, 1, 0, 0, 0, 0];
    } else if (lvl === 19) {
      arr = [4, 3, 3, 3, 2, 0, 0, 0, 0];
    } else if (lvl === 20) {
      arr = [4, 3, 3, 3, 2, 0, 0, 0, 0];
    }
    return arr;
  };
  const getThirdSpellSlots = () => {
    let arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    let lvl = parseInt(level);
    if (lvl === 1) {
      arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 2) {
      arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 3) {
      arr = [2, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 4) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 5) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 6) {
      arr = [3, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 7) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 8) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 9) {
      arr = [4, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 10) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 11) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 12) {
      arr = [4, 3, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 13) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 14) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 15) {
      arr = [4, 3, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 16) {
      arr = [4, 3, 3, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 17) {
      arr = [4, 3, 3, 0, 1, 0, 0, 0, 0];
    } else if (lvl === 18) {
      arr = [4, 3, 3, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 19) {
      arr = [4, 3, 3, 1, 0, 0, 0, 0, 0];
    } else if (lvl === 20) {
      arr = [4, 3, 3, 1, 0, 0, 0, 0, 0];
    }
    return arr;
  };
  const getWarlockSpellSlots = () => {
    let arr = [0, 0, 0, 0, 0, 0, 0, 0, 0];
    let lvl = parseInt(level);
    if (lvl === 1) {
      arr = [1, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 2) {
      arr = [2, 0, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 3) {
      arr = [0, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 4) {
      arr = [0, 2, 0, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 5) {
      arr = [0, 0, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 6) {
      arr = [0, 0, 2, 0, 0, 0, 0, 0, 0];
    } else if (lvl === 7) {
      arr = [0, 0, 0, 2, 0, 0, 0, 0, 0];
    } else if (lvl === 8) {
      arr = [0, 0, 0, 2, 0, 0, 0, 0, 0];
    } else if (lvl === 9) {
      arr = [0, 0, 0, 0, 2, 0, 0, 0, 0];
    } else if (lvl === 10) {
      arr = [0, 0, 0, 0, 2, 0, 0, 0, 0];
    } else if (lvl === 11) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 12) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 13) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 14) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 15) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 16) {
      arr = [0, 0, 0, 0, 3, 0, 0, 0, 0];
    } else if (lvl === 17) {
      arr = [0, 0, 0, 0, 4, 0, 0, 0, 0];
    } else if (lvl === 18) {
      arr = [0, 0, 0, 0, 4, 0, 0, 0, 0];
    } else if (lvl === 19) {
      arr = [0, 0, 0, 0, 4, 0, 0, 0, 0];
    } else if (lvl === 20) {
      arr = [0, 0, 0, 0, 4, 0, 0, 0, 0];
    }
    return arr;
  };

  return (
    <Container className="single-character-container">
      <Container>
        {slotLevels.map((level) => {
          return (
            <Row className="justify-content-md-center">
              <h2>Level {level} </h2>
              <Button variant="danger" onClick={() => decrementSlot(level - 1)}>
                -1
              </Button>
              <h2>{spellSlots[level - 1]}</h2>
              <Button
                variant="success"
                onClick={() => incrementSlot(level - 1)}
              >
                +1
              </Button>
            </Row>
          );
        })}
        <Row className="justify-content-md-center">
          <Button onClick={handleReset}>Reset Slots</Button>
        </Row>
      </Container>
    </Container>
  );
};

export default SpellSlots;
