import React, { Component } from "react";
import { Button, Col, Row, Container, ButtonGroup } from "react-bootstrap";

const HPCounter = ({ HP }) => {
  const [currentHP, setCurrentHP] = React.useState(0);

  // Create handleIncrement event handler
  const handleIncrement = () => setCurrentHP(currentHP + 1);
  const handleFiveIncrement = () => setCurrentHP(currentHP + 5);

  //Create handleDecrement event handler
  let handleDecrement = () => setCurrentHP(currentHP - 1);
  let handleFiveDecrement = () => setCurrentHP(currentHP - 5);

  const handleReset = () => setCurrentHP(parseInt(HP));

  return (
    <Container className="single-character-container-counter">
      <Row className="justify-content-center">
        <h1>Current HP</h1>
      </Row>
      <Row className="justify-content-center">
        <ButtonGroup>
          <Button variant="danger" onClick={handleFiveDecrement}>
            -5
          </Button>
          <Button variant="danger" onClick={handleDecrement}>
            -1
          </Button>
        </ButtonGroup>
        <h1 className="health-count">
          {currentHP}/{HP}
        </h1>
        <ButtonGroup>
          <Button variant="success" onClick={handleIncrement}>
            +1
          </Button>
          <Button variant="success" onClick={handleFiveIncrement}>
            +5
          </Button>
        </ButtonGroup>
      </Row>
      <Row className="justify-content-center">
        <Button onClick={handleReset}>Reset</Button>
      </Row>
    </Container>
  );
};

export default HPCounter;
